import sql from "@/app/api/utils/sql";
import {
  jsonNoStore,
  normalizeStateCode,
  requireAdminSessionOrReturnResponse,
} from "../utils";
import { normalizeCourtLevelSafe } from "@/app/api/utils/court-type-normalization";

export const dynamic = "force-dynamic";

function safeText(v) {
  const s = String(v ?? "").trim();
  return s.length ? s : null;
}

function safeBool(v) {
  if (v === true) return true;
  if (v === false) return false;
  return null;
}

function safeInt(v) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : null;
}

function normalizeSourceClass(v) {
  const s = String(v || "unknown")
    .trim()
    .toLowerCase();
  return s || "unknown";
}

function normalizeUrlLoose(rawUrl) {
  const u = safeText(rawUrl);
  if (!u) return null;

  try {
    const url = new URL(u);

    // normalize: drop hash, trim trailing slash (except root)
    url.hash = "";
    const str = url.toString();

    if (str.endsWith("/") && url.pathname !== "/") {
      return str.slice(0, -1);
    }

    return str;
  } catch {
    return u; // keep original string if URL parsing fails
  }
}

function inferDiscoverMode({ sourceClass, url }) {
  const cls = String(sourceClass || "").toLowerCase();
  if (cls === "pdf") {
    // PDFs are leaf nodes; no discovery.
    return "";
  }

  const u = String(url || "").toLowerCase();
  if (u.includes(".pdf")) {
    return "";
  }

  // Align with Rule Sources Manager discover_mode options.
  return "html_index";
}

export async function POST(request) {
  const { ok, response } = await requireAdminSessionOrReturnResponse();
  if (!ok) return response;

  try {
    const body = await request.json().catch(() => ({}));

    const state = normalizeStateCode(body?.state || body?.jurisdiction_code);
    if (!state || state.length !== 2) {
      return jsonNoStore(
        {
          ok: false,
          error: "BAD_STATE",
          message: "state must be 2-letter code",
        },
        { status: 400 },
      );
    }

    const rawUrl = body?.url || body?.source_url;
    const source_url = normalizeUrlLoose(rawUrl);
    if (!source_url) {
      return jsonNoStore(
        { ok: false, error: "URL_REQUIRED", message: "url is required" },
        { status: 400 },
      );
    }

    const source_key = safeText(body?.source_key);

    const source_name = safeText(body?.source_name) || source_url;

    const rawCourtType = safeText(body?.court_type);
    const court_type = rawCourtType
      ? normalizeCourtLevelSafe(rawCourtType) || rawCourtType
      : null;

    const rule_set = safeText(body?.rule_set);
    const authority_name = safeText(body?.authority_name || body?.authority);

    const source_class = normalizeSourceClass(body?.source_class);
    const content_type_hint = safeText(body?.content_type_hint);

    const is_authoritative = safeBool(body?.is_authoritative);
    const is_parser_eligible = safeBool(body?.is_parser_eligible);

    const family_key = safeText(body?.family_key);
    const family_label = safeText(body?.family_label);

    const preferred_pattern = safeText(
      body?.preferred_pattern ||
        body?.pattern_hint ||
        body?.parser_pattern_hint,
    );

    const priority = safeInt(body?.priority);

    const discover_mode =
      safeText(body?.discover_mode) ||
      inferDiscoverMode({ sourceClass: source_class, url: source_url });

    // Upsert match: (jurisdiction_code, source_key) OR (jurisdiction_code, source_url)
    const existingRows = await sql(
      `
      SELECT id
      FROM public.rule_sources
      WHERE jurisdiction_code = $1::varchar
        AND COALESCE(is_active, true) = true
        AND (
          ($2::text IS NOT NULL AND source_key = $2::text)
          OR source_url = $3::text
        )
      ORDER BY id DESC
      LIMIT 1
    `,
      [state, source_key, source_url],
    );

    const existingId = existingRows?.[0]?.id
      ? Number(existingRows[0].id)
      : null;

    if (!existingId) {
      const rows = await sql(
        `
        INSERT INTO public.rule_sources (
          jurisdiction_code,
          rule_type,
          source_key,
          source_name,
          source_url,
          last_verified,
          rule_set,
          authority_name,
          ingestion_method,
          is_active,
          court_type,
          source_class,
          content_type_hint,
          is_authoritative,
          is_parser_eligible,
          parser_pattern_hint,
          priority,
          family_key,
          family_label,
          family_root,
          discover_mode,
          parent_source_id,
          source_depth
        ) VALUES (
          $1::varchar,
          'parser',
          $2::text,
          $3::text,
          $4::text,
          CURRENT_DATE,
          $5::varchar,
          $6::varchar,
          'parser',
          true,
          $7::varchar,
          $8::text,
          $9::text,
          $10::boolean,
          $11::boolean,
          $12::text,
          $13::int,
          $14::text,
          $15::text,
          true,
          $16::text,
          NULL,
          0
        )
        RETURNING id
      `,
        [
          state,
          source_key,
          source_name,
          source_url,
          rule_set,
          authority_name,
          court_type,
          source_class,
          content_type_hint,
          is_authoritative === null ? true : is_authoritative,
          is_parser_eligible === null ? true : is_parser_eligible,
          preferred_pattern,
          priority === null ? 100 : priority,
          family_key,
          family_label,
          discover_mode,
        ],
      );

      return jsonNoStore({
        ok: true,
        action: "inserted",
        id: rows?.[0]?.id ? Number(rows[0].id) : null,
      });
    }

    // Update only fields that are provided, but ALWAYS enforce family_root=true and root identity.
    const sets = [
      "family_root = true",
      "parent_source_id = NULL",
      "source_depth = 0",
    ];
    const values = [existingId];
    let i = values.length;

    const addSet = (sqlFrag, val) => {
      i += 1;
      sets.push(sqlFrag.replace("$X", `$${i}`));
      values.push(val);
    };

    // Identity-ish fields
    if (source_key !== null) addSet("source_key = $X::text", source_key);
    if (source_name) addSet("source_name = $X::text", source_name);
    if (source_url) addSet("source_url = $X::text", source_url);

    if (court_type !== null) addSet("court_type = $X::varchar", court_type);
    if (rule_set !== null) addSet("rule_set = $X::varchar", rule_set);
    if (authority_name !== null)
      addSet("authority_name = $X::varchar", authority_name);

    if (source_class) addSet("source_class = $X::text", source_class);
    if (content_type_hint !== null)
      addSet("content_type_hint = $X::text", content_type_hint);

    if (is_authoritative !== null)
      addSet("is_authoritative = $X::boolean", is_authoritative);
    if (is_parser_eligible !== null)
      addSet("is_parser_eligible = $X::boolean", is_parser_eligible);

    if (preferred_pattern !== null)
      addSet("parser_pattern_hint = $X::text", preferred_pattern);

    if (priority !== null) addSet("priority = $X::int", priority);

    if (family_key !== null) addSet("family_key = $X::text", family_key);
    if (family_label !== null) addSet("family_label = $X::text", family_label);

    if (discover_mode !== null)
      addSet("discover_mode = $X::text", discover_mode);

    const q = `
      UPDATE public.rule_sources
      SET ${sets.join(", ")}, updated_at = NOW(), last_verified = CURRENT_DATE
      WHERE id = $1::int
      RETURNING id
    `;

    const updated = await sql(q, values);

    return jsonNoStore({
      ok: true,
      action: "updated",
      id: updated?.[0]?.id ? Number(updated[0].id) : existingId,
    });
  } catch (error) {
    console.error("[state-parser register-root] error", error);
    return jsonNoStore(
      { ok: false, error: error?.message || "Failed" },
      { status: 500 },
    );
  }
}

